ALTER TYPE "PermissionKey" ADD VALUE 'VIEW_ENVIRONMENTAL';
ALTER TYPE "PermissionKey" ADD VALUE 'MANAGE_ENVIRONMENTAL';
ALTER TYPE "DocumentEntityType" ADD VALUE 'ENVIRONMENTAL';
CREATE TYPE "EnvironmentalMetricType" AS ENUM ('ENERGY','ELECTRICITY','FUEL','WATER','WASTE','GHG_SCOPE_1','GHG_SCOPE_2','GHG_SCOPE_3','AIR_EMISSION','WASTEWATER','SPILL','OTHER');
CREATE TYPE "EnvironmentalDataStatus" AS ENUM ('DRAFT','SUBMITTED','APPROVED','REJECTED');
CREATE TYPE "EnvironmentalDataQuality" AS ENUM ('MEASURED','CALCULATED','ESTIMATED','SUPPLIER_PROVIDED');
CREATE TABLE "EnvironmentalMetricDefinition" ("id" TEXT NOT NULL,"organizationId" TEXT NOT NULL,"code" TEXT NOT NULL,"name" TEXT NOT NULL,"description" TEXT,"type" "EnvironmentalMetricType" NOT NULL,"sourceUnit" TEXT NOT NULL,"reportingUnit" TEXT NOT NULL,"conversionFactor" DOUBLE PRECISION NOT NULL DEFAULT 1,"methodology" TEXT,"isActive" BOOLEAN NOT NULL DEFAULT true,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL,CONSTRAINT "EnvironmentalMetricDefinition_pkey" PRIMARY KEY ("id"));
CREATE TABLE "EnvironmentalDataPoint" ("id" TEXT NOT NULL,"metricId" TEXT NOT NULL,"siteId" TEXT NOT NULL,"periodStart" TIMESTAMP(3) NOT NULL,"periodEnd" TIMESTAMP(3) NOT NULL,"value" DOUBLE PRECISION NOT NULL,"normalizedValue" DOUBLE PRECISION NOT NULL,"quality" "EnvironmentalDataQuality" NOT NULL DEFAULT 'MEASURED',"status" "EnvironmentalDataStatus" NOT NULL DEFAULT 'DRAFT',"evidenceSummary" TEXT,"notes" TEXT,"enteredById" TEXT NOT NULL,"approvedById" TEXT,"approvedAt" TIMESTAMP(3),"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL,CONSTRAINT "EnvironmentalDataPoint_pkey" PRIMARY KEY ("id"));
CREATE TABLE "EnvironmentalTarget" ("id" TEXT NOT NULL,"organizationId" TEXT NOT NULL,"metricId" TEXT NOT NULL,"name" TEXT NOT NULL,"baselineYear" INTEGER NOT NULL,"baselineValue" DOUBLE PRECISION NOT NULL,"targetYear" INTEGER NOT NULL,"targetValue" DOUBLE PRECISION NOT NULL,"description" TEXT,"isActive" BOOLEAN NOT NULL DEFAULT true,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL,CONSTRAINT "EnvironmentalTarget_pkey" PRIMARY KEY ("id"));
CREATE UNIQUE INDEX "EnvironmentalMetricDefinition_organizationId_code_key" ON "EnvironmentalMetricDefinition"("organizationId","code");CREATE INDEX "EnvironmentalMetricDefinition_organizationId_type_isActive_idx" ON "EnvironmentalMetricDefinition"("organizationId","type","isActive");CREATE UNIQUE INDEX "EnvironmentalDataPoint_metricId_siteId_periodStart_periodEnd_key" ON "EnvironmentalDataPoint"("metricId","siteId","periodStart","periodEnd");CREATE INDEX "EnvironmentalDataPoint_siteId_periodEnd_status_idx" ON "EnvironmentalDataPoint"("siteId","periodEnd","status");CREATE INDEX "EnvironmentalDataPoint_metricId_periodEnd_idx" ON "EnvironmentalDataPoint"("metricId","periodEnd");CREATE INDEX "EnvironmentalTarget_organizationId_isActive_idx" ON "EnvironmentalTarget"("organizationId","isActive");CREATE INDEX "EnvironmentalTarget_metricId_targetYear_idx" ON "EnvironmentalTarget"("metricId","targetYear");
ALTER TABLE "EnvironmentalMetricDefinition" ADD CONSTRAINT "EnvironmentalMetricDefinition_organizationId_fkey" FOREIGN KEY ("organizationId") REFERENCES "Organization"("id") ON DELETE CASCADE ON UPDATE CASCADE;ALTER TABLE "EnvironmentalDataPoint" ADD CONSTRAINT "EnvironmentalDataPoint_metricId_fkey" FOREIGN KEY ("metricId") REFERENCES "EnvironmentalMetricDefinition"("id") ON DELETE CASCADE ON UPDATE CASCADE;ALTER TABLE "EnvironmentalDataPoint" ADD CONSTRAINT "EnvironmentalDataPoint_siteId_fkey" FOREIGN KEY ("siteId") REFERENCES "Site"("id") ON DELETE CASCADE ON UPDATE CASCADE;ALTER TABLE "EnvironmentalDataPoint" ADD CONSTRAINT "EnvironmentalDataPoint_enteredById_fkey" FOREIGN KEY ("enteredById") REFERENCES "User"("id") ON DELETE RESTRICT ON UPDATE CASCADE;ALTER TABLE "EnvironmentalDataPoint" ADD CONSTRAINT "EnvironmentalDataPoint_approvedById_fkey" FOREIGN KEY ("approvedById") REFERENCES "User"("id") ON DELETE SET NULL ON UPDATE CASCADE;ALTER TABLE "EnvironmentalTarget" ADD CONSTRAINT "EnvironmentalTarget_organizationId_fkey" FOREIGN KEY ("organizationId") REFERENCES "Organization"("id") ON DELETE CASCADE ON UPDATE CASCADE;ALTER TABLE "EnvironmentalTarget" ADD CONSTRAINT "EnvironmentalTarget_metricId_fkey" FOREIGN KEY ("metricId") REFERENCES "EnvironmentalMetricDefinition"("id") ON DELETE CASCADE ON UPDATE CASCADE;
